} from "@repo/design-system/components/ui/accordion";
import type { Meta, StoryObj } from "@storybook/react";

/**
 * A vertically stacked set of interactive headings that each reveal a section
 * of content.
 */
const meta = {
  title: "ui/Accordion",
  component: Accordion,
  tags: ["autodocs"],
  argTypes: {
